import http from "node:http";
import express from "express";
import { Server as SocketIOServer, type Socket } from "socket.io";
import { RoomManager } from "../game/roomManager.js";
import type { EngineEvent } from "../game/types.js";

export interface AppServer {
  app: express.Express;
  httpServer: http.Server;
  io: SocketIOServer;
  roomManager: RoomManager;
  start: (port: number) => Promise<http.Server>;
  stop: () => Promise<void>;
}

interface UserContext {
  playerId: string;
  userName: string;
}

function isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseUserContext(req: express.Request): UserContext {
  const body = isObject(req.body) ? req.body : {};
  const userId = body.userId ?? req.header("x-user-id") ?? req.query.userId;
  const userName = body.userName ?? req.header("x-user-name") ?? req.query.userName ?? "Player";

  if (typeof userId !== "string" || userId.trim().length === 0) {
    throw new Error("userId is required");
  }

  if (typeof userName !== "string" || userName.trim().length === 0) {
    throw new Error("userName is required");
  }

  return {
    playerId: userId,
    userName,
  };
}

function emitTutorialEvent(roomManager: RoomManager, io: SocketIOServer, roomId: string, event: EngineEvent): void {
  const room = roomManager.getRoomById(roomId);
  if (!room || room.roomType !== "tutorial") {
    return;
  }

  const user = room.players.find((player) => !player.isBot);
  if (!user?.socketId) {
    return;
  }

  if (event.type === "tutorial_step_changed") {
    io.to(user.socketId).emit("tutorial:stepChanged", event.payload);
    return;
  }

  if (event.type === "tutorial_hint") {
    io.to(user.socketId).emit("tutorial:hint", event.payload);
    return;
  }

  if (event.type === "tutorial_completed") {
    io.to(user.socketId).emit("tutorial:completed", event.payload);
  }
}

function sanitizeError(error: unknown): { message: string } {
  if (error instanceof Error) {
    return { message: error.message };
  }
  return { message: "Unexpected error" };
}

export function createAppServer(options?: {
  tutorialReactionTimeoutMs?: number;
  multiplayerReactionTimeoutMs?: number;
  botDelayMs?: number;
}): AppServer {
  const app = express();
  app.use(express.json());

  app.use((req, res, next) => {
    res.header("Access-Control-Allow-Origin", "*");
    res.header("Access-Control-Allow-Methods", "GET,POST,OPTIONS");
    res.header("Access-Control-Allow-Headers", "Content-Type, x-user-id, x-user-name");
    if (req.method === "OPTIONS") {
      res.sendStatus(204);
      return;
    }
    next();
  });

  const httpServer = http.createServer(app);

  const io = new SocketIOServer(httpServer, {
    cors: {
      origin: "*",
      methods: ["GET", "POST"],
    },
  });

  const roomManager = new RoomManager({
    tutorialReactionTimeoutMs: options?.tutorialReactionTimeoutMs,
    multiplayerReactionTimeoutMs: options?.multiplayerReactionTimeoutMs,
    botDelayMs: options?.botDelayMs,
    onRoomEvent: ({ roomId, event }) => {
      if (event.type === "state_changed") {
        pushRoomSnapshots(roomId);
        return;
      }

      io.to(roomId).emit("game:event", event);
      emitTutorialEvent(roomManager, io, roomId, event);

      if (event.type === "player_left") {
        pushRoomSnapshots(roomId);
      }
    },
  });

  const socketToPlayer = new Map<string, string>();

  function pushRoomSnapshots(roomId: string): void {
    const room = roomManager.getRoomById(roomId);
    if (!room) {
      return;
    }

    for (const player of room.players) {
      if (!player.socketId) {
        continue;
      }
      io.to(player.socketId).emit("room:state", room.toSnapshot(player.id));
    }
  }

  function safeSocketHandler<T>(socket: Socket, fn: (payload: T, ack?: (res: unknown) => void) => void) {
    return (payload: T, ack?: (res: unknown) => void) => {
      try {
        fn(payload, ack);
      } catch (error) {
        const err = sanitizeError(error);
        socket.emit("error:event", err);
        if (ack) {
          ack({ ok: false, error: err.message });
        }
      }
    };
  }

  io.on("connection", (socket) => {
    socket.on(
      "session:attach",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const room = roomManager.getRoomByPlayer(payload.playerId);
        if (!room) {
          throw new Error("Room not found for player");
        }

        roomManager.markConnected(payload.playerId, socket.id);
        socketToPlayer.set(socket.id, payload.playerId);
        socket.join(room.roomId);
        io.to(socket.id).emit("room:state", room.toSnapshot(payload.playerId));

        if (ack) {
          ack({ ok: true, roomId: room.roomId, code: room.code });
        }
      }),
    );

    socket.on(
      "room:create",
      safeSocketHandler<{ playerId: string; playerName: string; roomType?: "multiplayer" | "tutorial" }>(socket, (payload, ack) => {
        const { room, snapshot } = roomManager.createLobby({
          hostId: payload.playerId,
          hostName: payload.playerName,
          socketId: socket.id,
          roomType: payload.roomType ?? "multiplayer",
        });
        socket.join(room.roomId);
        roomManager.markConnected(payload.playerId, socket.id);
        socketToPlayer.set(socket.id, payload.playerId);
        if (ack) {
          ack({ ok: true, code: room.code, roomId: room.roomId, snapshot });
        }
        pushRoomSnapshots(room.roomId);
      }),
    );

    socket.on(
      "room:join",
      safeSocketHandler<{ code: string; playerId: string; playerName: string }>(socket, (payload, ack) => {
        const { room, snapshot } = roomManager.joinLobby({
          code: payload.code,
          userId: payload.playerId,
          userName: payload.playerName,
          socketId: socket.id,
        });
        socket.join(room.roomId);
        roomManager.markConnected(payload.playerId, socket.id);
        socketToPlayer.set(socket.id, payload.playerId);
        if (ack) {
          ack({ ok: true, code: room.code, roomId: room.roomId, snapshot });
        }
        pushRoomSnapshots(room.roomId);
      }),
    );

    socket.on(
      "room:leave",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const room = roomManager.getRoomByPlayer(payload.playerId);
        const roomId = room?.roomId;
        roomManager.leaveRoom(payload.playerId);
        socketToPlayer.delete(socket.id);
        if (roomId) {
          socket.leave(roomId);
          pushRoomSnapshots(roomId);
        }
        if (ack) {
          ack({ ok: true });
        }
      }),
    );

    socket.on(
      "room:ready",
      safeSocketHandler<{ playerId: string; ready: boolean }>(socket, (payload, ack) => {
        const snapshot = roomManager.setReady(payload.playerId, payload.ready);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "room:addBot",
      safeSocketHandler<{
        playerId: string;
        difficulty: "Minion" | "Adept" | "Oracle";
        personality: "Cruel" | "Coward" | "Chaotic";
        name?: string;
      }>(socket, (payload, ack) => {
        const snapshot = roomManager.addBot(payload.playerId, {
          difficulty: payload.difficulty,
          personality: payload.personality,
          name: payload.name,
        });
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "room:start",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const snapshot = roomManager.startMatch(payload.playerId);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "room:snapshot",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const snapshot = roomManager.getSnapshot(payload.playerId);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "action:playCard",
      safeSocketHandler<{ playerId: string; cardId: string; targetId?: string; blackoutSuit?: "Ash" | "Blood" | "Bone" | "Mist" }>(
        socket,
        (payload, ack) => {
          const snapshot = roomManager.playCard(payload);
          if (ack) {
            ack({ ok: true, snapshot });
          }
        },
      ),
    );

    socket.on(
      "action:reaction",
      safeSocketHandler<{ playerId: string; cardId: string; redirectTargetId?: string }>(socket, (payload, ack) => {
        const snapshot = roomManager.reaction(payload);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "action:eclipseCall",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const snapshot = roomManager.eclipseCall(payload.playerId);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "action:drawCard",
      safeSocketHandler<{ playerId: string; endTurn?: boolean }>(socket, (payload, ack) => {
        const snapshot = roomManager.drawCard(payload.playerId, payload.endTurn ?? true);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on(
      "tutorial:skip",
      safeSocketHandler<{ playerId: string }>(socket, (payload, ack) => {
        const snapshot = roomManager.skipTutorial(payload.playerId);
        if (ack) {
          ack({ ok: true, snapshot });
        }
      }),
    );

    socket.on("disconnect", () => {
      const playerId = socketToPlayer.get(socket.id);
      if (!playerId) {
        return;
      }
      roomManager.markDisconnected(playerId);
      socketToPlayer.delete(socket.id);
    });
  });

  app.get("/health", (_req, res) => {
    res.json({ ok: true, service: "eclipse-club-backend" });
  });

  app.post("/tutorial/start", (req, res) => {
