        userId: playerId,
        userName,
      });
      res.json({
        ok: true,
        roomId: room.roomId,
        code: room.code,
        snapshot,
        progress,
      });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  app.get("/tutorial/progress", (req, res) => {
    try {
      const userId = req.query.userId;
      if (typeof userId !== "string") {
        throw new Error("userId is required");
      }
      res.json({
        ok: true,
        progress: roomManager.getTutorialProgress(userId),
      });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  return {
    app,
    httpServer,
    io,
    roomManager,
    start: (port: number) =>
      new Promise((resolve) => {
        httpServer.listen(port, () => resolve(httpServer));
      }),
    stop: () =>
      new Promise((resolve, reject) => {
        io.close(() => {
          httpServer.close((error) => {
            if (error) {
              reject(error);
              return;
            }
            resolve();
          });
        });
      }),
  };
