import type { AuthUser, ClubStats, SocialUser } from "../lib/api";
import { addFriend, getClubStats, getLeaderboard, listFriends, searchUsers } from "../lib/api";
import {
  BookOpen,
  CircleUser,
  Home,
  LogOut,
  PlusCircle,
  Shield,
  SlidersHorizontal,
  Sparkles,
  Swords,
  UserPlus2,
} from "lucide-react";

interface Props {
  user: AuthUser;
  settings: GameSettings;
  onSettingsChange: (patch: Partial<GameSettings>) => void;
  onLogout: () => void;
  onNavigate: (screen: "lobby" | "match" | "tutorial") => void;
}

type MenuTab = "home" | "grimorio" | "social" | "perfil";

const emptyClubStats: ClubStats = {
  players: 0,
  friendships: 0,
  avgLevel: 0,
};

export function MainMenuScreen({
  user,
  settings,
  onSettingsChange,
  onLogout,
  onNavigate,
}: Props) {
  const [tab, setTab] = useState<MenuTab>("home");
  const [showProfile, setShowProfile] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [clubStats, setClubStats] = useState<ClubStats>(emptyClubStats);
  const [leaderboard, setLeaderboard] = useState<AuthUser[]>([]);
  const [friends, setFriends] = useState<SocialUser[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<SocialUser[]>([]);
  const [socialLoading, setSocialLoading] = useState(false);
  const [socialError, setSocialError] = useState("");

  const winRate = useMemo(() => {
    if (!user.matches) {
      return 0;
    }
    return Math.round((user.wins / user.matches) * 100);
  }, [user.matches, user.wins]);

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      try {
        const [stats, board, currentFriends] = await Promise.all([
          getClubStats(),
          getLeaderboard(8),
          listFriends(),
        ]);
        if (cancelled) {
          return;
        }
        setClubStats(stats);
        setLeaderboard(board);
        setFriends(currentFriends);
      } catch {
        if (!cancelled) {
          setSocialError("No se pudo sincronizar datos sociales");
        }
      }
    };

    void load();
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;

    const runSearch = async () => {
      if (!searchQuery.trim()) {
        setSearchResults([]);
        setSocialError("");
        return;
      }

      setSocialLoading(true);
      try {
        const found = await searchUsers(searchQuery.trim(), 18);
        if (!cancelled) {
          setSearchResults(found);
          setSocialError("");
        }
      } catch (error) {
        if (!cancelled) {
          setSocialError(error instanceof Error ? error.message : "Busqueda no disponible");
        }
      } finally {
        if (!cancelled) {
          setSocialLoading(false);
        }
      }
    };

    const timer = window.setTimeout(runSearch, 280);
    return () => {
      cancelled = true;
      window.clearTimeout(timer);
    };
  }, [searchQuery]);

  const handleAddFriend = async (targetUserId: string) => {
    try {
      const updatedFriends = await addFriend({ targetUserId });
      setFriends(updatedFriends);
      if (searchQuery.trim()) {
        const found = await searchUsers(searchQuery.trim(), 18);
        setSearchResults(found);
      }
    } catch (error) {
      setSocialError(error instanceof Error ? error.message : "No se pudo agregar amigo");
    }
  };

  return (
    <div className="relative min-h-[100dvh] w-full overflow-x-hidden text-[var(--eclipse-text)] font-sans">
      <FogBackground />

      <div className="relative z-20 flex min-h-[100dvh] flex-col">
        <header className="flex items-start justify-between px-6 pt-6 sm:px-8">
          <div className="space-y-1">
            <p className="eclipse-title text-2xl leading-none tracking-[0.16em] sm:text-3xl sm:tracking-[0.18em]">
              Eclipse
            </p>
            <p className="eclipse-title text-2xl leading-none tracking-[0.16em] sm:text-3xl sm:tracking-[0.18em]">
              Club
            </p>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-right">
              <p className="eclipse-subtitle text-[10px] text-[var(--eclipse-gold)]">Nivel {user.level}</p>
              <p className="text-sm font-semibold">{user.displayName}</p>
            </div>
            <button
              type="button"
              onClick={() => {
                setTab("perfil");
                setShowProfile(true);
              }}
              className="flex h-10 w-10 items-center justify-center rounded-full border border-[rgba(103,80,165,0.7)] bg-[rgba(33,24,62,0.9)]"
            >
              <CircleUser className="h-5 w-5 text-[var(--eclipse-text)]" />
            </button>
          </div>
        </header>

        <main className="flex flex-1 flex-col px-6 pb-32 pt-4 sm:px-8">
          <motion.div
            className="mx-auto flex h-36 w-36 items-center justify-center rounded-full border border-[rgba(200,154,23,0.18)] sm:h-44 sm:w-44"
            initial={{ scale: 0.93, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.7 }}
          >
            <div className="flex h-[4.5rem] w-[4.5rem] items-center justify-center rounded-full bg-[rgba(200,154,23,0.12)] text-[var(--eclipse-gold)] sm:h-20 sm:w-20">
              <Sparkles className="h-10 w-10 sm:h-12 sm:w-12" />
            </div>
          </motion.div>

          <div className="mt-4 text-center">
            <h1 className="eclipse-title text-4xl leading-none tracking-[0.03em] sm:text-5xl">Inframundo</h1>
            <p className="eclipse-subtitle mt-2 text-[11px] text-[var(--eclipse-gold)]">
              El ritual comienza
            </p>
          </div>

          {tab === "home" && (
            <div className="mt-6 flex flex-col gap-3">
              <Button
                variant="primary"
                size="xl"
                onClick={() => onNavigate("match")}
                className="w-full justify-start rounded-2xl px-6"
              >
                <Swords className="h-5 w-5 text-[var(--eclipse-gold)]" />
                Partida rapida
              </Button>

              <Button
                variant="secondary"
                size="xl"
                onClick={() => onNavigate("tutorial")}
                className="w-full justify-start rounded-2xl px-6"
              >
                <BookOpen className="h-5 w-5 text-[var(--eclipse-gold)]" />
                Practica guiada
              </Button>

              <div className="mt-1 grid grid-cols-2 gap-3">
                <Button
                  variant="secondary"
                  size="lg"
                  onClick={() => onNavigate("lobby")}
                  className="rounded-2xl text-sm"
                >
                  <PlusCircle className="h-4 w-4 text-[var(--eclipse-gold)]" />
                  Crear sala
                </Button>
                <Button
                  variant="secondary"
                  size="lg"
                  onClick={() => onNavigate("lobby")}
                  className="rounded-2xl text-sm"
                >
                  <UserPlus2 className="h-4 w-4 text-[var(--eclipse-gold)]" />
                  Unirse
                </Button>
              </div>

              <Button
                variant="ghost"
                size="md"
                className="mt-1 w-full rounded-xl"
                onClick={() => setShowSettings(true)}
              >
                <SlidersHorizontal className="h-4 w-4" />
                Ajustes del sistema
              </Button>
            </div>
          )}

          {tab === "grimorio" && (
            <section className="eclipse-panel mt-6 space-y-4 rounded-2xl p-4">
              <h2 className="eclipse-title text-sm">Grimorio de combate</h2>
              <p className="text-sm leading-relaxed eclipse-muted">
                Juega por palo o numero. Cada carta de sombra te carga 1 punto de Shadow (maximo 6).
              </p>
              <div className="grid gap-2 text-sm">
                <p className="rounded-xl border border-[rgba(91,69,148,0.55)] bg-[rgba(17,13,31,0.86)] px-3 py-2">
                  Espejo Negro (reaccion): devuelve un ataque al atacante durante la ventana de reaccion.
                </p>
                <p className="rounded-xl border border-[rgba(91,69,148,0.55)] bg-[rgba(17,13,31,0.86)] px-3 py-2">
                  Ritual ShadowSteal: gasta Shadow para robar recurso al rival y romper su combo.
                </p>
                <p className="rounded-xl border border-[rgba(91,69,148,0.55)] bg-[rgba(17,13,31,0.86)] px-3 py-2">
                  Con 1 carta restante debes cantar ECLIPSE o recibes penalizacion.
                </p>
              </div>
              <Button
                variant="ritual"
                size="lg"
                className="w-full rounded-xl"
                onClick={() => onNavigate("tutorial")}
              >
                Ver tutorial completo
              </Button>
            </section>
          )}

          {tab === "social" && (
            <section className="eclipse-panel mt-6 space-y-4 rounded-2xl p-4">
              <h2 className="eclipse-title text-sm">Social</h2>
              <p className="text-sm leading-relaxed eclipse-muted">
                Busca usuarios reales del club y agregalos para jugar salas privadas.
              </p>

              <input
                value={searchQuery}
                onChange={(event) => setSearchQuery(event.currentTarget.value)}
                placeholder="Buscar por usuario o nombre..."
                className="w-full rounded-xl border border-[rgba(90,68,146,0.72)] bg-[rgba(12,10,22,0.94)] px-3 py-2 text-sm outline-none"
              />

              {socialLoading && <p className="text-xs eclipse-muted">Buscando jugadores...</p>}
              {socialError && (
                <p className="rounded-xl border border-[rgba(175,74,98,0.62)] bg-[rgba(52,16,30,0.86)] px-3 py-2 text-xs text-rose-200">
                  {socialError}
                </p>
              )}

              {searchQuery.trim() && (
                <div className="space-y-2">
                  {searchResults.length === 0 && !socialLoading && (
                    <p className="text-xs eclipse-muted">No hay resultados para esa busqueda.</p>
                  )}
                  {searchResults.map((item) => (
                    <div
                      key={item.id}
                      className="flex items-center justify-between rounded-xl border border-[rgba(86,67,139,0.6)] bg-[rgba(14,11,26,0.9)] px-3 py-2"
                    >
                      <div>
                        <p className="text-sm font-semibold">{item.displayName}</p>
                        <p className="eclipse-muted text-xs">@{item.username} · Nivel {item.level}</p>
                      </div>
                      {item.isFriend ? (
                        <span className="text-xs text-emerald-300">Amigo</span>
                      ) : (
                        <Button
                          variant="secondary"
                          size="sm"
                          className="rounded-lg"
                          onClick={() => handleAddFriend(item.id)}
                        >
                          + Amigo
                        </Button>
                      )}
                    </div>
                  ))}
                </div>
              )}

              <div className="rounded-xl border border-[rgba(87,67,139,0.58)] bg-[rgba(15,11,27,0.88)] p-3">
                <p className="mb-2 text-xs eclipse-subtitle text-[var(--eclipse-accent-soft)]">Mis aliados</p>
                <div className="space-y-2">
                  {friends.length === 0 && <p className="text-xs eclipse-muted">Aun no tienes amigos agregados.</p>}
                  {friends.slice(0, 5).map((ally) => (
                    <div key={ally.id} className="flex items-center justify-between text-sm">
                      <span>{ally.displayName}</span>
                      <span className="text-xs eclipse-muted">Nivel {ally.level}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <Button
                  variant="secondary"
                  size="lg"
                  className="rounded-xl"
                  onClick={() => onNavigate("lobby")}
                >
                  <PlusCircle className="h-4 w-4 text-[var(--eclipse-gold)]" />
                  Crear
                </Button>
                <Button
                  variant="secondary"
                  size="lg"
                  className="rounded-xl"
                  onClick={() => onNavigate("lobby")}
                >
                  <UserPlus2 className="h-4 w-4 text-[var(--eclipse-gold)]" />
                  Unirse
                </Button>
              </div>
            </section>
          )}

          {tab === "perfil" && (
            <section className="eclipse-panel mt-6 space-y-4 rounded-2xl p-4">
              <h2 className="eclipse-title text-sm">Perfil</h2>
              <div className="space-y-2 text-sm">
                <p className="font-semibold">{user.displayName}</p>
                <p className="eclipse-muted">Usuario: @{user.username}</p>
                <p className="eclipse-muted">Nivel: {user.level}</p>
                <p className="eclipse-muted">XP: {user.xp}</p>
                <p className="eclipse-muted">Victorias: {user.wins}</p>
                <p className="eclipse-muted">Partidas: {user.matches}</p>
                <p className="eclipse-muted">Winrate: {winRate}%</p>
              </div>
              <Button
                variant="secondary"
                size="lg"
                className="w-full rounded-xl"
                onClick={() => setShowProfile(true)}
              >
                <CircleUser className="h-4 w-4 text-[var(--eclipse-gold)]" />
                Ver detalles
              </Button>
            </section>
          )}

          <div className="mt-auto flex flex-wrap items-center justify-between gap-3 pt-6">
            <div className="flex items-center gap-2">
              {leaderboard.slice(0, 3).map((topUser, index) => (
                <div
                  key={topUser.id}
                  className={`eclipse-panel-soft flex h-8 min-w-8 items-center justify-center rounded-full px-2 text-[10px] font-bold ${
                    index === 0 ? "text-[var(--eclipse-gold)]" : "eclipse-muted"
                  }`}
                >
                  {topUser.displayName.slice(0, 2).toUpperCase()}
                </div>
              ))}
            </div>
            <div className="eclipse-subtitle flex items-center gap-2 text-[9px] eclipse-muted sm:text-[10px]">
              <span className="h-2 w-2 rounded-full bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.85)]" />
              {clubStats.players} en el club
            </div>
          </div>
        </main>

        <nav className="absolute inset-x-0 bottom-0 z-30">
          <div className="eclipse-bottom-nav grid grid-cols-4 px-4 pb-5 pt-3">
            <button
              type="button"
              onClick={() => setTab("home")}
              className={`flex flex-col items-center gap-1 ${tab === "home" ? "text-[var(--eclipse-gold)]" : "text-[var(--eclipse-text-faint)]"}`}
            >
              <Home className="h-5 w-5" />
              <span className="eclipse-subtitle text-[9px]">Inicio</span>
            </button>
            <button
              type="button"
              onClick={() => setTab("grimorio")}
              className={`flex flex-col items-center gap-1 ${tab === "grimorio" ? "text-[var(--eclipse-gold)]" : "text-[var(--eclipse-text-faint)]"}`}
            >
              <BookOpen className="h-5 w-5" />
              <span className="eclipse-subtitle text-[9px]">Grimorio</span>
            </button>
            <button
              type="button"
              onClick={() => setTab("social")}
              className={`flex flex-col items-center gap-1 ${tab === "social" ? "text-[var(--eclipse-gold)]" : "text-[var(--eclipse-text-faint)]"}`}
            >
              <UserPlus2 className="h-5 w-5" />
              <span className="eclipse-subtitle text-[9px]">Social</span>
            </button>
            <button
              type="button"
              onClick={() => setTab("perfil")}
              className={`flex flex-col items-center gap-1 ${tab === "perfil" ? "text-[var(--eclipse-gold)]" : "text-[var(--eclipse-text-faint)]"}`}
            >
              <Shield className="h-5 w-5" />
              <span className="eclipse-subtitle text-[9px]">Perfil</span>
            </button>
          </div>
        </nav>
      </div>

      <OverlayPanel open={showSettings} title="Ajustes" onClose={() => setShowSettings(false)}>
        <SettingsControls settings={settings} onChange={onSettingsChange} />
        <div className="mt-3 space-y-2">
          <Button variant="secondary" size="md" className="w-full rounded-xl" onClick={() => setShowSettings(false)}>
            Cerrar
          </Button>
          <Button variant="danger" size="md" className="w-full rounded-xl" onClick={onLogout}>
            <LogOut className="h-4 w-4" />
            Cerrar sesion
          </Button>
        </div>
      </OverlayPanel>

      <OverlayPanel open={showProfile} title="Perfil" onClose={() => setShowProfile(false)}>
        <div className="space-y-3 text-sm">
          <p className="font-semibold">{user.displayName}</p>
          <p className="eclipse-muted">Nivel: {user.level}</p>
          <p className="eclipse-muted">XP: {user.xp}</p>
          <p className="eclipse-muted">Amigos: {friends.length}</p>
          <p className="eclipse-muted">Club: {clubStats.players} jugadores</p>
          <div className="rounded-xl border border-[rgba(88,68,140,0.6)] bg-[rgba(15,12,28,0.86)] p-3">
            <p className="eclipse-subtitle text-[9px] text-[var(--eclipse-accent-soft)]">Top actual</p>
            <div className="mt-2 space-y-1.5">
              {leaderboard.slice(0, 3).map((top, index) => (
                <p key={top.id} className="text-xs eclipse-muted">
                  #{index + 1} {top.displayName} · Nivel {top.level}
                </p>
              ))}
            </div>
          </div>
          <Button variant="secondary" size="md" className="w-full rounded-xl" onClick={() => setShowProfile(false)}>
            Volver
          </Button>
        </div>
      </OverlayPanel>
    </div>
  );
}
EOF"}

